namespace test_reaction {

ValiditySnapshot test_react_validity(int initialValue) {
    ReactVar<int> var(std::ref(initialValue));
    int copy = var.get();
    ValiditySnapshot snapshot;

    // Check validity and equality before close
    snapshot.firstValidBeforeClose = var.is_valid();
    snapshot.copiesEqualBeforeClose = (var.get() == copy);

    // Close the reactive node
    var.close();

    // Check validity and equality after close with exception handling
    snapshot.firstValidAfterClose = var.is_valid();
    try {
        int value = var.get();
        snapshot.copiesEqualAfterClose = (value == copy);
        snapshot.equalityCheckFailedAfterClose = false;
    } catch (const std::runtime_error&) {
        snapshot.copiesEqualAfterClose = false;
        snapshot.equalityCheckFailedAfterClose = true;
    }

    return snapshot;
}

